from agent import *from models.products import *def process_indexpage(data, context, session):   for u in data.xpath('//li[@id="menu-item-718"]//li/a'):       url = u.xpath('@href').string()       catName = u.xpath('.//text()').string()       session.queue(Request(url), process_page, dict(context, catName=catName ) )def process_page(data, context, session):   for u in data.xpath('//div[@class="archive-text"]//h2/a[regexp:test(text(),"Test |test ")]'):       rName = u.xpath('text()').string()       url = u.xpath('@href').string()       session.queue(Request(url), process_post, dict(context, rUrl=url, rName=rName) )   nxtLink = data.xpath('//div[@class="pagination"]/span[@class="current"]/following-sibling::a[1][regexp:test(text(),"\d")]/@href').string()   if nxtLink:       session.queue(Request(nxtLink), process_page, dict(context))       def process_post(data, context, session):    rTitle = context['rName']    date = data.xpath('//div[@id="title-main"]/span[@class="post-byline"]/a[@rel="author"]/following-sibling::text()[1]').string(multiple=True)    author = data.xpath('//div[@id="title-main"]/span[@class="post-byline"]/a[@rel="author"]/text()').string()    pName = context['rName']    pCategory = context['catName']    excerpt = data.xpath('/descendant::div[@id="content-area"][1]/descendant::p[string-length(normalize-space(.))>150][1]//text()').string(multiple=True)    concl = data.xpath('/descendant::div[@id="content-area"][1]/descendant::h1[regexp:test(normalize-space(.),"^Conclusion")]/following::p[string-length(normalize-space(.))>150][1]//text()|/descendant::div[@id="content-area"][1]/descendant::p[regexp:test(normalize-space(.),"^Conclusion")]/following::p[string-length(normalize-space(.))>150][1]//text()').string(multiple=True)    cons = data.xpath('//div[@id="content-area"]//p[regexp:test(normalize-space(.),"^- ")]//text()[preceding::p[regexp:test(normalize-space(.),"^Les moins")]]').strings()    pros = data.xpath('//div[@id="content-area"]//p[regexp:test(normalize-space(.),"^\+ ")]//text()[preceding::p[regexp:test(normalize-space(.),"^Les plus")]]').strings()    cons = [f.strip().strip('+-:') for f in cons if f.strip()]    pros = [f.strip().strip('+-:') for f in pros if f.strip()]    review = Review()    review.title = rTitle    review.ssid = review.title    review.date = date    review.type = "pro"     review.authors.append(Person(name=author,ssid=author))    if concl:        review.properties.append(ReviewProperty(type="conclusion", value=concl))    review.properties.append(ReviewProperty(type="excerpt", value=excerpt))    review.url = context['rUrl']    grade = data.xpath('//div[@id="content-area"]//p[regexp:test(normalize-space(.),"Note Globale : \d+ ")]//text()').string() or ""    grade = re_search_once(r'(\d+)', grade)    if grade:        review.grades.append(Grade(value=grade, best = 100, worst=0,name = 'Note Globale',type='overall'))    pr = Product(name=pName, ssid=review.ssid, url=review.url)    pr.reviews.append(review)    pr.category = pCategory    if pros:        review.properties.append(ReviewProperty(name="Pros", type="pros", value=pros))    if cons :        review.properties.append(ReviewProperty(name="Cons", type="cons", value=cons))    session.emit(pr) def run(context, session):   session.queue(Request('http://wearemobians.com/category/articles/'), process_indexpage, {})